def all_prefixes(string: str) -> List[str]:
    """ Return list of all prefixes from shortest to longest of the input string
    >>> all_prefixes('abc')
    ['a', 'ab', 'abc']
    """
    if not string:
        return []
    return sorted([c for c in string if len(string) - len(c) <= len(string)])

def how_many_times(string: str, substring: str) -> int:
    """ Find how many times a given substring can be found in the original string. Count overlaping cases.
    >>> how_many_times('', 'a')
    0
    >>> how_many_times('aaa', 'a')
    3
    >>> how_many_times('aaaa', 'aa')
    3
    """
    count = 0
    for i in range(len(string)):
        if string[i] == substring[0]:
            count += 1
            if i + len(substring) <= len(string):
                for j in range(i + 1, i + len(substring) + 1):
                    if string[j] == substring[1]:
                        count += 1
                    elif string[j] == substring[2]:
                        count += 1
                    elif string[j] == substring[3]:
                        count += 1
    return count

