def sort_numbers(numbers: str) -> str:
    """ Input is a space-delimited string of numberals from 'zero' to 'nine'.
    Valid choices are 'zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight' and 'nine'.
    Return the string with numbers sorted from smallest to largest
    >>> sort_numbers('three one five')
    'one three five'
    """
    valid_values = ['zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine']
    def is_valid(char: str) -> bool:
        return char in valid_values

    numbers_str = [n.strip() for n in numbers.split()]
    if not all(is_valid(n) for n in numbers_str):
        raise ValueError("All numbers must be valid digits")

    def convert_to_int(n: str) -> int:
        return int(n)

    def sort_numbers_v2(numbers_str: str) -> str:
        return sorted(numbers_str, key=convert_to_int)

    return sort_numbers_v2(numbers_str)

