def prime_fib(n: int):
    """
    prime_fib returns n-th number that is a Fibonacci number and it's also prime.
    >>> prime_fib(1)
    2
    >>> prime_fib(2)
    3
    >>> prime_fib(3)
    5
    >>> prime_fib(4)
    13
    >>> prime_fib(5)
    89
    """
    if n < 0:
        raise ValueError("Input n must be non-negative")

    def is_prime(k: int) -> bool:
        if k <= 1:
            return False
        if k <= 3:
            return True
        if k % 2 == 0 or k % 3 == 0:
            return False
        for i in range(5, int(k**0.5) + 1, 6):
            if k % i == 0 or k % (i + 2) == 0:
                return False
        return True

    fib_numbers = [0, 1, 1]
    while fib_numbers[-1] < n:
        fib_numbers.append(fib_numbers[-1] + fib_numbers[-2])

    for fib in fib_numbers:
        if is_prime(fib):
            return fib

    raise ValueError(f"No such number exists for n={n}")

def prime_fib(n: int):
    """
    prime_fib returns n-th number that is a Fibonacci number and it's also prime.
    >>> prime_fib(1)
    2
    >>> prime_fib(2)
    3
    >>> prime_fib(3)
    5
    >>> prime_fib(4)
    13
    >>> prime_fib(5)
    89
    """
    def is_fibonacci(x):
        """Check if x is a Fibonacci number."""
        if x < 1:
            return False
        a, b = 0, 1
        while b <= x:
            a, b = b, a + b
        return True

    def is_prime(x):
        """Check if x is a prime number."""
        if x <= 1:
            return False
        if x <= 3:
            return True
        if x % 2 == 0 or x % 3 == 0:
            return False
        i = 5
        while i * i <= x:
            if x % i == 0 or x % (i + 2) == 0:
                return False
            i += 6
        return True

    def is_prime_fibonacci(x):
        """Check if x is a Fibonacci number that is also prime."""
        return is_fibonacci(x) and is_prime(x)

    def fib(n):
        """Return n-th Fibonacci number starting from 0."""
        if n <= 0:
            return 0
        if n == 1:
            return 1
        a, b = 0, 1
        for _ in range(2, n):
            a, b = b, a + b
        return b

    def prime_fib_impl(n):
        """Helper to compute the n-th Fibonacci number that is also prime."""
        fib_val = fib(n)
        return is_prime_fibonacci(fib_val)

    return prime_fib_impl(n)

