        for i in range(3, int(n ** 0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    memo = {}

    def get_next(n: int) -> int:
        """Returns the next Fibonacci number that is also prime."""
        if n in memo:
            return memo[n]

        # Calculate next Fibonacci number
        if is_fib(n + 1):
            return n + 1
        # Check if n + 1 is prime
        if is_prime(n + 1):
            memo[n + 1] = n + 1
            return n + 1
        # If not, continue searching
        for i in range(2, n + 2):
            if is_fib(i):
                if is_prime(i):
                    memo[n] = i
                    return i
                else:
                    # If i is not prime, check the next Fibonacci number after it
                    memo[i] = i
                    return get_next(i + 1)
            else:
                # If i is not Fibonacci, check the next Fibonacci number after it
                memo[i] = i
                return get_next(i + 1)

    return get_next(n)

