    alphabet = "abcdefghijklmnopqrstuvwxyz"
    index_map = {letter: i for i, letter in enumerate(alphabet)}

    def rotate(shift):
        return ''.join(
            alphabet[index_map[i] + shift % len(alphabet) for i in range(len(alphabet))]
