    # Generate primes up to n using trial division
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    # Generate primes up to n
    primes = [num for num in range(2, n + 1) if is_prime(num)]

    # Filter and return the first n primes
    return primes[:n]

def count_up_to(n):
    """Implement a function that takes an non-negative integer and returns an array of the first n
    integers that are prime numbers and less than n.
    for example:
    count_up_to(5) => [2,3]
    count_up_to(11) => [2,3,5,7]
    count_up_to(0) => []
    count_up_to(20) => [2,3,5,7,11,13,17,19]
    count_up_to(1) => []
    count_up_to(18) => [2,3,5,7,11,13,17]
    """
    if n <= 0:
        return []

    result = []
    i = 2

    while i * i <= n:
        if i not in [2,3]:
            is_prime = True
            for j in range(i, n + 1, i):
                if n % j == 0:
                    is_prime = False
                    break
            if is_prime:
                result.append(i)
        i += 1

    return result[:n]

