    >>> count_nums([]) == 0
    >>> count_nums([-1, 11, -11]) == 1
    >>> count_nums([1, 1, 2]) == 3
    """
    def get_signed_digits(n):
        if n < 0:
            digits = []
            while n > 0:
                n = n // -1
                digits.append(-n % 10)
            return digits
        else:
            digits = []
            while n > 0:
                n = n // 10
                digits.append(n % 10)
            return digits

    count = 0
    for num in arr:
        if num < 0:
