def match_parens(lst):
    '''
    You are given a list of two strings, both strings consist of open
    parentheses '(' or close parentheses ')' only.
    Your job is to check if it is possible to concatenate the two strings in
    some order, that the resulting string will be good.
    A string S is considered to be good if and only if all parentheses in S
    are balanced. For example: the string '(())()' is good, while the string
    '())' is not.
    Return 'Yes' if there's a way to make a good string, and return 'No' otherwise.

    Examples:
    match_parens(['()(', ')']) == 'Yes'
    match_parens([')', ')']) == 'No'
    '''
    def backtrack(idx1, idx2, s1, s2):
        if idx1 == len(s1) or idx2 == len(s2):
            return (s1 + s2).count('(') == 0 and (s1 + s2).count(')') == 0

        if s1[idx1] == '(' and s2[idx2] == ')':
            backtrack(idx1 + 1, idx2 + 1, s1, s2)
        elif s1[idx1] == ')' and s2[idx2] == '(':
            backtrack(idx1, idx2 + 1, s1, s2)
        elif s1[idx1] == '(':
            backtrack(idx1, idx2, s1, s2)
        elif s1[idx1] == ')':
            backtrack(idx1, idx2 + 1, s1, s2)
        else:
            return

    for idx1 in range(len(s1)):
        for idx2 in range(len(s2)):
            s1 = lst[0]
            s2 = lst[1]
            backtrack(0, 0, s1, s2)
            if not backtrack(0, 0, s1, s2):
                return 'No'

    return 'Yes'

def match_parens(lst):
    """
    You are given a list of two strings, both strings consist of open
    parentheses '(' or close parentheses ')' only.
    Your job is to check if it is possible to concatenate the two strings in
    some order, that the resulting string will be good.
    A string S is considered to be good if and only if all parentheses in S
    are balanced. For example: the string '(())()' is good, while the string
    '())' is not.
    Return 'Yes' if there's a way to make a good string, and return 'No' otherwise.

    Examples:
    match_parens(['()(', ')']) == 'Yes'
    match_parens([')', ')']) == 'No'
    """

    def is_balanced(s):
        if not s:
            return True
        stack = []
        for char in s:
            if char == '(':
                stack.append(1)
            elif char == ')':
                if not stack:
                    return False
                stack.pop()
        return len(stack) == 0

    if len(lst) == 1:
        return is_balanced(lst[0])

    if len(lst) == 2:
        return is_balanced(lst[0]) or is_balanced(lst[1])

    # Try all permutations of concatenating lst[0] and lst[1]
    for perm in itertools.permutations(lst):
        if is_balanced("".join(perm[0]), "".join(perm[1])):
            return True

    return False

