    Given a non-empty array of integers arr and an integer k, return
    the sum of the elements with at most two digits from the first k elements of arr.

    Example:

        Input: arr = [111,21,3,4000,5,6,7,8,9], k = 4
        Output: 24 # sum of 21 + 3

    Constraints:
        1. 1 <= len(arr) <= 100
        2. 1 <= k <= len(arr)
    """
    if not arr:
        return 0

    def is_at_most_two_digits(n):
        if n == 0:
            return False
        if n == 1:
            return True
        if len(str(n)) <= 2:
            return True
        return False

    sum_result = 0
    seen = set()  # To track elements we have already added to avoid duplicates

    for x in arr[:k]:
        if x > 0:
            if is_at_most_two_digits(x):
                if x not in seen:
                    seen.add(x)
                    sum_result += x
        else:
            pass  # Elements are 0, handled as "at most two digits"

    return sum_result

def valid_date(date):
    """You have to write a function which validates a given date string and
    returns True if the date is valid otherwise False.
    The date is valid if all of the following rules are satisfied:
    1. The date string is not empty.
    2. The number of days is not less than 1 or higher than 31 days for months 1,3,5,7,8,10,12. And the number of days is not less than 1 or higher than 30 days for months 4,6,9,11. And, the number of days is not less than 1 or higher than 29 for the month 2.
    3. The months should not be less than 1 or higher than 12.
    4. The date should be in the format: mm-dd-yyyy

    for example: 
    valid_date('03-11-2000') => True

    valid_date('15-01-2012') => False

    valid_date('04-0-2040') => False

    valid_date('06-04-2020') => True

    valid_date('06/04/2020') => False
    """
    # Parse the date string into components: month, day, year
    month, day, year = map(int, date.split('-'))

    # Rule 3: Check if month is between 1 and 12 (inclusive)
    if month < 1 or month > 12:
        return False

    # Rule 2: Determine the number of days for the given month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Valid days: 1, 31
        days = [1, 31]
    elif month in [4, 6, 9, 11]:
        # Valid days: 30
        days = [30]
    else:
        # Month 2 is valid only for 29 days
        days = [29]

    # Rule 1: Check if day is between 1 and 31 (inclusive)
    if day < 1 or day > 31:
        return False

    # Rule 2: Check if the number of days is not less than 1 or higher than 31 for months 1,3,5,7,8,10,12. And the number of days is not less than 1 or higher than 30 days for months 4,6,9,11. And, the number of days is not less than 1 or higher than 29 for the month 2.
    # Note: For month 2, the number of days must be <= 29.
    if day <= 0:
        return False

    if days == [1, 31]:
        if day <= 1:
            return False
        if day > 31:
            return False
    elif days == [30]:
        if day <= 30:
            return False
        if day > 31:
            return False
    elif days == [29]:
        if day <= 29:
            return False
        if day > 31:
            return False

