def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace, if no whitespaces exists in the text you
    should split on commas ',' if no commas exists you should return the number of lower-case letters with odd order in the
    alphabet, ord('a') = 0, ord('b') = 1, ... ord('z') = 25
    Examples
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") == 3 
    '''
    # Split by whitespace
    if ' ' in txt:
        return txt.split()
    # Check for commas
    if ',' in txt:
        return txt.split(',')
    # Calculate number of lower-case letters with odd order in the alphabet
    count = 0
    for i in range(ord('a'), ord('z') + 1):
        if i.islower() and i % 2 != 0:
            count += 1
    return count

def split_words(txt):
    words = txt.split()
    if not words:
        return 0
    lower_words = [w.lower() for w in words]
    letters = [ord(c) for c in lower_words if c.isalpha()]
    odd_letters = [ord(c) for c in letters if c % 2 == 1]
    return sum(odd_letters)

def tri(n):
    """Returns a list of the first n + 1 numbers of the Tribonacci sequence."""
    if n < 0:
        raise ValueError("Input n must be non-negative.")

    fib_sequence = [1]  # tri(1)
    for i in range(2, n + 1):
        if i % 2 == 0:
            tri_val = 1 + i // 2
        else:
            tri_val = fib_sequence[-1] + fib_sequence[-2] + fib_sequence[-3]
        fib_sequence.append(tri_val)

    return fib_sequence

