def check_if_last_char_is_a_letter(txt):
    if not txt:
        return False

    last_char = txt[-1]

    # Check if last character is a letter
    if not last_char.isalpha():
        return False

    # Check if the last character is a word separator (space, newline, etc.)
    if last_char in " \n\r\t":
