def right_angle_triangle(a, b, c):
    # Check if any two sides form a right angle by checking the square of one side equals the sum of squares of the other two
    # Using Pythagorean theorem: a^2 + b^2 = c^2 (with a, b, c being the side lengths)
    if a ** 2 + b ** 2 != c ** 2:
        return False
    # Check if the triangle is valid (triangle inequality)
    if a + b <= c or a + c <= b or b + c <= a:
        return False
    return True

